import React from 'react';

export default function Breadcrumbs({ items, separator = '/', maxItems = 0 }) {
  let shown = items;
  let collapsed = false;
  if (maxItems > 0 && items.length > maxItems) {
    shown = [items[0], ...items.slice(items.length - (maxItems - 1))];
    collapsed = true;
  }

  const sep = { color: '#999', margin: '0 8px' };
  const link = { color: '#2563eb', textDecoration: 'none' };

  return (
    <nav aria-label="Breadcrumb">
      <ol style={{ display: 'flex', flexWrap: 'wrap', listStyle: 'none', padding: 0, margin: 0, alignItems: 'center' }}>
        {shown.map((crumb, i) => {
          const isLast = i === shown.length - 1;
          return (
            <li key={crumb.href || crumb.label} style={{ display: 'flex', alignItems: 'center' }}>
              {i > 0 && <span aria-hidden="true" style={sep}>{separator}</span>}
              {collapsed && i === 1 && (
                <>
                  <span aria-hidden="true" style={{ color: '#999' }}>…</span>
                  <span aria-hidden="true" style={sep}>{separator}</span>
                </>
              )}
              {isLast ? (
                <span aria-current="page" style={{ color: '#333', fontWeight: 600 }}>{crumb.label}</span>
              ) : (
                <a href={crumb.href} style={link}>{crumb.label}</a>
              )}
            </li>
          );
        })}
      </ol>
    </nav>
  );
}

