import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Crumb { label: string; href: string; }

@Component({
  selector: 'app-breadcrumbs',
  template: `
    <nav aria-label="Breadcrumb">
      <ol style="display: flex; flex-wrap: wrap; align-items: center; list-style: none; padding: 0; margin: 0;">
        <li *ngFor="let crumb of shown; let i = index" style="display: flex; align-items: center;">
          <span *ngIf="i > 0" aria-hidden="true" style="color: #999; margin: 0 8px;">{{ separator }}</span>
          <ng-container *ngIf="collapsed && i === 1">
            <span aria-hidden="true" style="color: #999;">…</span>
            <span aria-hidden="true" style="color: #999; margin: 0 8px;">{{ separator }}</span>
          </ng-container>
          <span *ngIf="i === shown.length - 1; else link" aria-current="page" style="color: #333; font-weight: 600;">{{ crumb.label }}</span>
          <ng-template #link><a [href]="crumb.href" style="color: #2563eb; text-decoration: none;">{{ crumb.label }}</a></ng-template>
        </li>
      </ol>
    </nav>
  `,
})
export class BreadcrumbsComponent {
  @Input() items: Crumb[] = [];
  @Input() separator = '/';
  @Input() maxItems = 0;

  get shown(): Crumb[] {
    if (this.maxItems > 0 && this.items.length > this.maxItems) {
      return [this.items[0], ...this.items.slice(this.items.length - (this.maxItems - 1))];
    }
    return this.items;
  }

  get collapsed(): boolean {
    return this.shown.length < this.items.length;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Breadcrumbs Demo</h1>
      <h3>Full</h3>
      <app-breadcrumbs [items]="items"></app-breadcrumbs>
      <h3>Collapsed (maxItems = 3)</h3>
      <app-breadcrumbs [items]="items" [maxItems]="3"></app-breadcrumbs>
    </div>
  `,
})
export class AppComponent {
  items: Crumb[] = [
    { label: 'Home', href: '#home' },
    { label: 'Electronics', href: '#electronics' },
    { label: 'Computers', href: '#computers' },
    { label: 'Laptops', href: '#laptops' },
    { label: 'ProBook 14', href: '#probook' },
  ];
}

@NgModule({
  declarations: [AppComponent, BreadcrumbsComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
